+		{"medium", ptrInt(1024), 8192 + 1024},
+		// Explicit maxTokens (10000) > medium budget (8192): no adjustment.
+		{"medium", ptrInt(10000), 10000},
+		// Low budget (1024) < default maxTokens (4096): no adjustment.
+		{"low", nil, 4096},
+	}
+	for _, tc := range cases {
+		name := tc.effort
